/**
 * GENERATED COMPONENT — ContactDetail
 * Domain: CRM
 * Primitive: useComposableCard
 * Generated by: AI from hook + domain context
 */

import { useComposableCard } from '../../hooks/composable'

interface Contact {
  id: string
  name: string
  email: string
  company: string
  status: 'lead' | 'active' | 'churned'
}

interface ContactDetailProps {
  componentId: string
  listenToComponent?: string
}

export function ContactDetail({ componentId, listenToComponent }: ContactDetailProps) {
  const { data, hasData, emitAction } = useComposableCard<Contact>({
    componentId,
    listenToComponent,
  })

  if (!hasData || !data) {
    return (
      <div className="flex items-center justify-center h-full text-gray-400 text-sm">
        Select a contact to view details
      </div>
    )
  }

  return (
    <div className="flex flex-col gap-6">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div>
          <h2 className="text-xl font-semibold text-gray-900">{data.name}</h2>
          <p className="text-sm text-gray-500">{data.company}</p>
        </div>
        <span className={`text-sm px-3 py-1 rounded-full ${
          data.status === 'active' ? 'bg-green-100 text-green-800' :
          data.status === 'lead' ? 'bg-yellow-100 text-yellow-800' :
          'bg-red-100 text-red-800'
        }`}>
          {data.status}
        </span>
      </div>

      {/* Info */}
      <div className="space-y-3">
        <div className="flex justify-between text-sm">
          <span className="text-gray-500">Email</span>
          <span className="text-gray-900">{data.email}</span>
        </div>
        <div className="flex justify-between text-sm">
          <span className="text-gray-500">Company</span>
          <span className="text-gray-900">{data.company}</span>
        </div>
        <div className="flex justify-between text-sm">
          <span className="text-gray-500">ID</span>
          <span className="text-gray-900 font-mono text-xs">{data.id}</span>
        </div>
      </div>

      {/* Actions */}
      <div className="flex gap-2 pt-4 border-t border-gray-100">
        <button
          onClick={() => emitAction('edit')}
          className="flex-1 px-3 py-2 text-sm bg-blue-500 text-white rounded-lg hover:bg-blue-600 transition-colors"
        >
          Edit
        </button>
        <button
          onClick={() => emitAction('email')}
          className="flex-1 px-3 py-2 text-sm bg-gray-100 text-gray-700 rounded-lg hover:bg-gray-200 transition-colors"
        >
          Send Email
        </button>
        <button
          onClick={() => emitAction('delete')}
          className="px-3 py-2 text-sm text-red-600 hover:bg-red-50 rounded-lg transition-colors"
        >
          Delete
        </button>
      </div>
    </div>
  )
}
